import {
  type CSSProperties,
  type FocusEvent,
  forwardRef,
  type InputHTMLAttributes,
  type KeyboardEvent,
  type MouseEvent,
  type ReactNode,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { type ComponentSize, useDisabled, useSize } from '../../config-provider';
import { Icon } from '../Icon';

export type InputType =
  | 'text'
  | 'password'
  | 'textarea'
  | 'email'
  | 'url'
  | 'tel'
  | 'number'
  | 'search';

export interface InputProps
  extends Omit<
    InputHTMLAttributes<HTMLInputElement>,
    | 'value'
    | 'defaultValue'
    | 'onChange'
    | 'size'
    | 'type'
    | 'prefix'
    | 'onFocus'
    | 'onBlur'
    | 'onKeyDown'
  > {
  /** Controlled value. */
  value?: string;
  /** Initial value for the uncontrolled mode. */
  defaultValue?: string;
  /** Fired with the next value on every change. */
  onChange?: (value: string) => void;
  /** Input type. `textarea` renders a `<textarea>`. */
  type?: InputType;
  /** Size. Falls back to the nearest ConfigProvider. */
  size?: ComponentSize;
  /** Disable the control. */
  disabled?: boolean;
  /** Show a clear button when the field has a value. */
  clearable?: boolean;
  /** Toggleable password visibility (only for `type="password"`). */
  showPassword?: boolean;
  /** Placeholder text. */
  placeholder?: string;
  /** Make the field read-only. */
  readOnly?: boolean;
  /** Maximum number of characters. */
  maxLength?: number;
  /** Show a character counter (requires `maxLength`). */
  showWordLimit?: boolean;
  /** Content rendered before the input, inside the wrapper. */
  prefixIcon?: ReactNode;
  /** Content rendered after the input, inside the wrapper. */
  suffixIcon?: ReactNode;
  /** Content rendered before the wrapper, as a group addon. */
  prepend?: ReactNode;
  /** Content rendered after the wrapper, as a group addon. */
  append?: ReactNode;
  /** Number of visible rows for `type="textarea"`. */
  rows?: number;
  /** Native `name` attribute. */
  name?: string;
  /** Native `id` attribute. */
  id?: string;
  /** Native `autocomplete` attribute. */
  autoComplete?: string;
  /** Fired on focus. */
  onFocus?: (event: FocusEvent<HTMLInputElement | HTMLTextAreaElement>) => void;
  /** Fired on blur. */
  onBlur?: (event: FocusEvent<HTMLInputElement | HTMLTextAreaElement>) => void;
  /** Fired on key down. */
  onKeyDown?: (event: KeyboardEvent<HTMLInputElement | HTMLTextAreaElement>) => void;
  /** Fired when the clear button is pressed. */
  onClear?: () => void;
  /** Extra class on the root element. */
  className?: string;
  /** Extra style on the root element. */
  style?: CSSProperties;
}

function ClearIcon() {
  return (
    <svg viewBox="0 0 1024 1024" xmlns="http://www.w3.org/2000/svg">
      <path
        fill="currentColor"
        d="M512 64a448 448 0 1 1 0 896 448 448 0 0 1 0-896zm0 393.664L407.936 353.6a38.4 38.4 0 1 0-54.336 54.336L457.664 512 353.6 616.064a38.4 38.4 0 1 0 54.336 54.336L512 566.336 616.064 670.4a38.4 38.4 0 1 0 54.336-54.336L566.336 512 670.4 407.936a38.4 38.4 0 1 0-54.336-54.336L512 457.664z"
      />
    </svg>
  );
}

function EyeIcon() {
  return (
    <svg viewBox="0 0 1024 1024" xmlns="http://www.w3.org/2000/svg">
      <path
        fill="currentColor"
        d="M512 160c320 0 512 352 512 352S832 864 512 864 0 512 0 512s192-352 512-352zm0 64c-225.28 0-384.128 208.064-436.8 288 52.608 79.872 211.456 288 436.8 288 225.28 0 384.128-208.064 436.8-288-52.608-79.872-211.456-288-436.8-288zm0 64a224 224 0 1 1 0 448 224 224 0 0 1 0-448zm0 64a160 160 0 1 0 0 320 160 160 0 0 0 0-320z"
      />
    </svg>
  );
}

function EyeOffIcon() {
  return (
    <svg viewBox="0 0 1024 1024" xmlns="http://www.w3.org/2000/svg">
      <path
        fill="currentColor"
        d="M876.8 156.8a32 32 0 0 1 0 45.248l-67.2 67.2C903.872 339.776 970.24 442.88 1004.8 512 952.128 591.872 793.28 800 512 800c-78.4 0-148.736-16.192-210.688-41.6l-78.464 78.4a32 32 0 1 1-45.248-45.248l45.248-45.248L876.8 156.8a32 32 0 0 1 45.248 0zM512 224c-225.28 0-384.128 208.064-436.8 288 31.616 47.872 95.36 130.624 191.872 192.128l79.616-79.616A224 224 0 0 1 624.512 320.512L688 257.024A468.48 468.48 0 0 0 512 224zm224 288c0-22.336-3.264-43.904-9.344-64.256L431.744 742.656A224 224 0 0 0 736 512z"
      />
    </svg>
  );
}

export const Input = forwardRef<HTMLInputElement | HTMLTextAreaElement, InputProps>(function Input(
  props,
  ref,
) {
  const {
    value,
    defaultValue,
    onChange,
    type = 'text',
    size: sizeProp,
    disabled: disabledProp,
    clearable = false,
    showPassword = false,
    placeholder,
    readOnly = false,
    maxLength,
    showWordLimit = false,
    prefixIcon,
    suffixIcon,
    prepend,
    append,
    rows = 2,
    name,
    id,
    autoComplete,
    onFocus,
    onBlur,
    onKeyDown,
    onClear,
    className,
    style,
    ...rest
  } = props;

  const ns = useNamespace('input');
  const textareaNs = useNamespace('textarea');
  const size = useSize(sizeProp);
  const disabled = useDisabled(disabledProp);

  const isControlled = value !== undefined;
  const [inner, setInner] = useState(defaultValue ?? '');
  const current = isControlled ? value : inner;

  const [focused, setFocused] = useState(false);
  const [passwordVisible, setPasswordVisible] = useState(false);

  const update = (next: string) => {
    if (!isControlled) setInner(next);
    onChange?.(next);
  };

  const handleClear = () => {
    update('');
    onClear?.();
  };

  // Keep focus on the field when activating a suffix control with the pointer.
  const preventBlur = (event: MouseEvent) => {
    event.preventDefault();
  };

  const wordCount = (
    <span className={ns.e('count')}>
      {current.length}
      {maxLength !== undefined ? ` / ${maxLength}` : ''}
    </span>
  );

  if (type === 'textarea') {
    const classes = cls(
      textareaNs.b(),
      size !== 'default' && textareaNs.m(size),
      textareaNs.is('disabled', disabled),
      textareaNs.is('exceed', maxLength !== undefined && current.length > maxLength),
      className,
    );
    return (
      <div className={classes} style={style}>
        <textarea
          {...(rest as React.TextareaHTMLAttributes<HTMLTextAreaElement>)}
          ref={ref as React.Ref<HTMLTextAreaElement>}
          className={textareaNs.e('inner')}
          value={current}
          placeholder={placeholder}
          disabled={disabled}
          readOnly={readOnly}
          maxLength={maxLength}
          rows={rows}
          name={name}
          id={id}
          autoComplete={autoComplete}
          onChange={(event) => update(event.target.value)}
          onFocus={(event) => {
            setFocused(true);
            onFocus?.(event);
          }}
          onBlur={(event) => {
            setFocused(false);
            onBlur?.(event);
          }}
          onKeyDown={onKeyDown}
        />
        {showWordLimit && maxLength !== undefined && wordCount}
      </div>
    );
  }

  const showClear = clearable && !disabled && !readOnly && current.length > 0;
  const showPasswordToggle = showPassword && type === 'password' && !disabled && !readOnly;
  const inputType = type === 'password' && passwordVisible ? 'text' : type;
  const hasSuffix = showClear || showPasswordToggle || suffixIcon || (showWordLimit && maxLength !== undefined);

  const classes = cls(
    ns.b(),
    size !== 'default' && ns.m(size),
    ns.is('disabled', disabled),
    ns.is('focus', focused),
    prepend !== undefined && prepend !== null && ns.is('prepend'),
    append !== undefined && append !== null && ns.is('append'),
    className,
  );

  return (
    <div className={classes} style={style}>
      {prepend !== undefined && prepend !== null && (
        <div className={ns.b('group__prepend')}>{prepend}</div>
      )}
      <div className={ns.e('wrapper')}>
        {prefixIcon && (
          <span className={ns.e('prefix')}>
            <Icon className={ns.e('icon')}>{prefixIcon}</Icon>
          </span>
        )}
        <input
          {...rest}
          ref={ref as React.Ref<HTMLInputElement>}
          className={ns.e('inner')}
          type={inputType}
          value={current}
          placeholder={placeholder}
          disabled={disabled}
          readOnly={readOnly}
          maxLength={maxLength}
          name={name}
          id={id}
          autoComplete={autoComplete}
          onChange={(event) => update(event.target.value)}
          onFocus={(event) => {
            setFocused(true);
            onFocus?.(event);
          }}
          onBlur={(event) => {
            setFocused(false);
            onBlur?.(event);
          }}
          onKeyDown={onKeyDown}
        />
        {hasSuffix && (
          <span className={ns.e('suffix')}>
            {showClear && (
              <button
                type="button"
                className={cls(ns.e('icon'), ns.e('clear'))}
                aria-label="Clear"
                onMouseDown={preventBlur}
                onClick={handleClear}
              >
                <Icon>
                  <ClearIcon />
                </Icon>
              </button>
            )}
            {showPasswordToggle && (
              <button
                type="button"
                className={cls(ns.e('icon'), ns.e('password'))}
                aria-label={passwordVisible ? 'Hide password' : 'Show password'}
                onMouseDown={preventBlur}
                onClick={() => setPasswordVisible((visible) => !visible)}
              >
                <Icon>{passwordVisible ? <EyeIcon /> : <EyeOffIcon />}</Icon>
              </button>
            )}
            {showWordLimit && maxLength !== undefined && wordCount}
            {suffixIcon && <Icon className={ns.e('icon')}>{suffixIcon}</Icon>}
          </span>
        )}
      </div>
      {append !== undefined && append !== null && (
        <div className={ns.b('group__append')}>{append}</div>
      )}
    </div>
  );
});

.ec-input {
  --ec-input-text-color: var(--ec-text-color-regular);
  --ec-input-border-color: var(--ec-border-color);
  --ec-input-hover-border-color: var(--ec-border-color-hover);
  --ec-input-focus-border-color: var(--ec-color-primary);
  --ec-input-bg-color: var(--ec-fill-color-blank);
  --ec-input-icon-color: var(--ec-text-color-placeholder);
  --ec-input-placeholder-color: var(--ec-text-color-placeholder);
  --ec-input-border-radius: var(--ec-border-radius-base);
  --ec-input-height: var(--ec-component-size);
  --ec-input-font-size: var(--ec-font-size-base);

  display: inline-flex;
  width: 100%;
  box-sizing: border-box;
  font-size: var(--ec-input-font-size);
  line-height: var(--ec-input-height);
}

.ec-input__wrapper {
  display: inline-flex;
  flex-grow: 1;
  align-items: center;
  gap: 6px;
  box-sizing: border-box;
  width: 100%;
  height: var(--ec-input-height);
  padding: 1px 11px;
  background-color: var(--ec-input-bg-color);
  background-image: none;
  border-radius: var(--ec-input-border-radius);
  cursor: text;
  transition: var(--ec-transition-box-shadow, var(--ec-transition-all));
  box-shadow: 0 0 0 1px var(--ec-input-border-color) inset;
}

.ec-input__wrapper:hover {
  box-shadow: 0 0 0 1px var(--ec-input-hover-border-color) inset;
}

.ec-input.is-focus .ec-input__wrapper,
.ec-input__wrapper:focus-within {
  box-shadow: 0 0 0 1px var(--ec-input-focus-border-color) inset;
}

.ec-input__inner {
  flex-grow: 1;
  width: 100%;
  min-width: 0;
  height: 100%;
  padding: 0;
  margin: 0;
  font-family: inherit;
  font-size: inherit;
  line-height: var(--ec-input-height);
  color: var(--ec-input-text-color);
  background: none;
  border: none;
  outline: none;
  appearance: none;
}

.ec-input__inner::placeholder {
  color: var(--ec-input-placeholder-color);
}

.ec-input__prefix,
.ec-input__suffix {
  display: inline-flex;
  flex-shrink: 0;
  align-items: center;
  gap: 6px;
  white-space: nowrap;
  color: var(--ec-input-icon-color);
}

.ec-input__icon {
  display: inline-flex;
  align-items: center;
  color: var(--ec-input-icon-color);
}

.ec-input__clear,
.ec-input__password {
  display: inline-flex;
  align-items: center;
  padding: 0;
  margin: 0;
  font-size: inherit;
  color: var(--ec-input-icon-color);
  background: none;
  border: none;
  outline: none;
  cursor: pointer;
  appearance: none;
  transition: var(--ec-transition-color);
}

.ec-input__clear:hover,
.ec-input__password:hover {
  color: var(--ec-text-color-secondary);
}

.ec-input__clear:focus-visible,
.ec-input__password:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: 1px;
  border-radius: var(--ec-border-radius-base);
}

.ec-input__count {
  display: inline-flex;
  align-items: center;
  font-size: var(--ec-font-size-extra-small);
  line-height: 1;
  color: var(--ec-text-color-placeholder);
}

/* ---- Disabled ---- */
.ec-input.is-disabled .ec-input__wrapper {
  background-color: var(--ec-disabled-bg-color);
  box-shadow: 0 0 0 1px var(--ec-disabled-border-color) inset;
  cursor: not-allowed;
}

.ec-input.is-disabled .ec-input__inner {
  color: var(--ec-disabled-text-color);
  -webkit-text-fill-color: var(--ec-disabled-text-color);
  cursor: not-allowed;
}

.ec-input.is-disabled .ec-input__inner::placeholder {
  color: var(--ec-disabled-text-color);
}

.ec-input.is-disabled .ec-input__clear,
.ec-input.is-disabled .ec-input__password {
  cursor: not-allowed;
}

/* ---- Group (prepend / append) ---- */
.ec-input-group__prepend,
.ec-input-group__append {
  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  padding: 0 20px;
  white-space: nowrap;
  color: var(--ec-text-color-regular);
  background-color: var(--ec-fill-color-light);
  border-radius: var(--ec-input-border-radius);
}

.ec-input-group__prepend {
  border-top-right-radius: 0;
  border-bottom-right-radius: 0;
}

.ec-input-group__append {
  border-top-left-radius: 0;
  border-bottom-left-radius: 0;
}

.ec-input.is-prepend .ec-input__wrapper {
  border-top-left-radius: 0;
  border-bottom-left-radius: 0;
}

.ec-input.is-append .ec-input__wrapper {
  border-top-right-radius: 0;
  border-bottom-right-radius: 0;
}

/* ---- Sizes ---- */
.ec-input--large {
  --ec-input-height: var(--ec-component-size-large);
  --ec-input-font-size: var(--ec-font-size-medium);
}

.ec-input--small {
  --ec-input-height: var(--ec-component-size-small);
  --ec-input-font-size: var(--ec-font-size-extra-small);
}

/* ---- Textarea ---- */
.ec-textarea {
  --ec-input-text-color: var(--ec-text-color-regular);
  --ec-input-border-color: var(--ec-border-color);
  --ec-input-hover-border-color: var(--ec-border-color-hover);
  --ec-input-focus-border-color: var(--ec-color-primary);
  --ec-input-bg-color: var(--ec-fill-color-blank);
  --ec-input-placeholder-color: var(--ec-text-color-placeholder);
  --ec-input-border-radius: var(--ec-border-radius-base);
  --ec-input-font-size: var(--ec-font-size-base);

  position: relative;
  display: inline-block;
  width: 100%;
  box-sizing: border-box;
  font-size: var(--ec-input-font-size);
  vertical-align: bottom;
}

.ec-textarea__inner {
  display: block;
  box-sizing: border-box;
  width: 100%;
  padding: 5px 11px;
  font-family: inherit;
  font-size: inherit;
  line-height: 1.5;
  color: var(--ec-input-text-color);
  background-color: var(--ec-input-bg-color);
  border: none;
  border-radius: var(--ec-input-border-radius);
  outline: none;
  resize: vertical;
  appearance: none;
  box-shadow: 0 0 0 1px var(--ec-input-border-color) inset;
  transition: var(--ec-transition-box-shadow, var(--ec-transition-all));
}

.ec-textarea__inner::placeholder {
  color: var(--ec-input-placeholder-color);
}

.ec-textarea__inner:hover {
  box-shadow: 0 0 0 1px var(--ec-input-hover-border-color) inset;
}

.ec-textarea__inner:focus {
  box-shadow: 0 0 0 1px var(--ec-input-focus-border-color) inset;
}

.ec-textarea .ec-input__count {
  position: absolute;
  right: 10px;
  bottom: 5px;
  background-color: var(--ec-input-bg-color);
}

.ec-textarea.is-disabled .ec-textarea__inner {
  color: var(--ec-disabled-text-color);
  background-color: var(--ec-disabled-bg-color);
  box-shadow: 0 0 0 1px var(--ec-disabled-border-color) inset;
  cursor: not-allowed;
}

.ec-textarea.is-disabled .ec-textarea__inner::placeholder {
  color: var(--ec-disabled-text-color);
}

.ec-textarea--large {
  --ec-input-font-size: var(--ec-font-size-medium);
}

.ec-textarea--small {
  --ec-input-font-size: var(--ec-font-size-extra-small);
}
